export function getOrganizedData(): VocabCategory[] {
  const categoryMap: Record<string, VocabWord[]> = {};
  vocabData.forEach(word => {
    if (!categoryMap[word.category]) categoryMap[word.category] = [];
    categoryMap[word.category].push(word);
  });

  return categories.map(cat => ({
    ...cat,
    words: categoryMap[cat.name] || [],
  })).filter(cat => cat.words.length > 0);
}
